#!/usr/bin/env python3
"""Health check script for local Prefect E2E stack.

Verifies all services are healthy and creates work pools if needed.
Usage: python scripts/local_stack_health.py
"""
import asyncio
import sys
import httpx
import asyncpg
import redis.asyncio as redis
from datetime import datetime

# Service configurations
SERVICES = {
 "prefect-postgres": {
 "type": "postgres",
 "dsn": "postgresql://prefect:prefect@localhost:5433/prefect",
 "port": 5433,
 },
 "prefect-redis": {
 "type": "redis",
 "url": "redis://localhost:6380",
 "port": 6380,
 },
 "prefect-server": {
 "type": "http",
 "url": "http://localhost:4200/api/health",
 "port": 4200,
 },
 "app-postgres": {
 "type": "postgres",
 "dsn": "postgresql://app_user:app_password@localhost:5434/agencheck_app",
 "port": 5434,
 },
}

PREFECT_API_URL = "http://localhost:4200/api"
WORK_POOL_NAME = "voice-pool"


async def check_postgres(name: str, dsn: str) -> tuple[bool, str]:
 """Check PostgreSQL connectivity."""
 try:
 conn = await asyncpg.connect(dsn, timeout=5)
 await conn.fetchval("SELECT 1")
 await conn.close()
 return True, "Connected"
 except Exception as e:
 return False, str(e)


async def check_redis(name: str, url: str) -> tuple[bool, str]:
 """Check Redis connectivity."""
 try:
 client = redis.from_url(url, socket_timeout=5)
 pong = await client.ping()
 await client.aclose()
 return pong, "PONG" if pong else "No response"
 except Exception as e:
 return False, str(e)


async def check_http(name: str, url: str) -> tuple[bool, str]:
 """Check HTTP endpoint."""
 try:
 async with httpx.AsyncClient(timeout=5) as client:
 resp = await client.get(url)
 return resp.status_code == 200, f"HTTP {resp.status_code}"
 except Exception as e:
 return False, str(e)


async def check_worker_logs() -> tuple[bool, str]:
 """Check if worker is polling (via Prefect API)."""
 try:
 async with httpx.AsyncClient(timeout=5) as client:
 # Check work pool exists and has workers
 resp = await client.get(f"{PREFECT_API_URL}/work_pools/{WORK_POOL_NAME}")
 if resp.status_code == 404:
 return False, "Work pool not found"
 if resp.status_code == 200:
 pool_data = resp.json()
 return True, f"Pool '{WORK_POOL_NAME}' exists"
 return False, f"HTTP {resp.status_code}"
 except Exception as e:
 return False, str(e)


async def create_work_pool() -> tuple[bool, str]:
 """Create voice-pool work pool if it doesn't exist."""
 try:
 async with httpx.AsyncClient(timeout=10) as client:
 # Check if exists
 resp = await client.get(f"{PREFECT_API_URL}/work_pools/{WORK_POOL_NAME}")
 if resp.status_code == 200:
 return True, "Already exists"

 # Create work pool
 resp = await client.post(
 f"{PREFECT_API_URL}/work_pools/",
 json={
 "name": WORK_POOL_NAME,
 "type": "process",
 "description": "Work pool for voice verification flows",
 }
 )
 if resp.status_code in (200, 201):
 return True, "Created"
 return False, f"HTTP {resp.status_code}: {resp.text}"
 except Exception as e:
 return False, str(e)


async def check_app_tables() -> tuple[bool, str]:
 """Verify app tables exist in app-postgres."""
 required_tables = ["cases", "verification_subjects", "university_contacts", "background_tasks"]
 dsn = SERVICES["app-postgres"]["dsn"]

 try:
 conn = await asyncpg.connect(dsn, timeout=5)
 existing = await conn.fetch("""
 SELECT table_name FROM information_schema.tables
 WHERE table_schema = 'public' AND table_name = ANY()
 """, required_tables)
 await conn.close()

 existing_names = {r["table_name"] for r in existing}
 missing = set(required_tables) - existing_names

 if missing:
 return False, f"Missing tables: {missing}"
 return True, f"All {len(required_tables)} tables exist"
 except Exception as e:
 return False, str(e)


